     1тЖТ/**
     2тЖТ * MMS Chaos Monkey - Bow-Wave Generator
     3тЖТ *
     4тЖТ * DEMO ONLY - Not for production use.
     5тЖТ *
     6тЖТ * Purpose: If the client's data is well-maintained (no bow-wave), the demo loses impact.
     7тЖТ * This feature artificially compresses PM schedules to force a visible bow-wave.
     8тЖТ *
     9тЖТ * Usage:
    10тЖТ * - URL param: ?chaos=true
    11тЖТ * - Shift+Click on BowWaveIndicator
    12тЖТ *
    13тЖТ * Pitch: "This is your data as-is. Now, let's simulate a 3-month
    14тЖТ *        supply chain disruption..." (Toggle) тЖТ "See that wave forming?"
    15тЖТ *
    16тЖТ * @see specs/009-demo-application.md Section 9.3.3
    17тЖТ */
    18тЖТ
    19тЖТimport type { ProjectedPM } from './types';
    20тЖТ
    21тЖТ// =============================================================================
    22тЖТ// Types
    23тЖТ// =============================================================================
    24тЖТ
    25тЖТ/** Configuration for chaos monkey disruption */
    26тЖТexport interface ChaosConfig {
    27тЖТ  /** How long the "disruption" lasts in months (default: 3) */
    28тЖТ  delayMonths?: number;
    29тЖТ  /** Start month of disruption (default: 6 months from now) */
    30тЖТ  disruptionStartMonth?: number;
    31тЖТ  /** What percentage of PMs to affect (default: 0.7 = 70%) */
    32тЖТ  affectRate?: number;
    33тЖТ  /** Random seed for reproducibility (optional) */
    34тЖТ  seed?: number;
    35тЖТ}
    36тЖТ
    37тЖТ/** Result of chaos monkey application */
    38тЖТexport interface ChaosResult {
    39тЖТ  /** Original projections (unmodified) */
    40тЖТ  original: ProjectedPM[];
    41тЖТ  /** Modified projections with bow-wave effect */
    42тЖТ  modified: ProjectedPM[];
    43тЖТ  /** Description of the disruption for demo narration */
    44тЖТ  description: string;
    45тЖТ  /** Statistics about the disruption */
    46тЖТ  stats: {
    47тЖТ    /** Number of PMs affected */
    48тЖТ    affected: number;
    49тЖТ    /** Number of PMs unchanged */
    50тЖТ    unchanged: number;
    51тЖТ    /** Average delay in days */
    52тЖТ    avgDelayDays: number;
    53тЖТ    /** Peak month after disruption */
    54тЖТ    peakMonth: string;
    55тЖТ    /** Peak month PM count */
    56тЖТ    peakCount: number;
    57тЖТ  };
    58тЖТ}
    59тЖТ
    60тЖТ// =============================================================================
    61тЖТ// Seeded Random for Reproducibility
    62тЖТ// =============================================================================
    63тЖТ
    64тЖТclass SeededRandom {
    65тЖТ  private seed: number;
    66тЖТ
    67тЖТ  constructor(seed: number) {
    68тЖТ    this.seed = seed;
    69тЖТ  }
    70тЖТ
    71тЖТ  next(): number {
    72тЖТ    this.seed = (this.seed * 1103515245 + 12345) & 0x7fffffff;
    73тЖТ    return this.seed / 0x7fffffff;
    74тЖТ  }
    75тЖТ
    76тЖТ  range(min: number, max: number): number {
    77тЖТ    return Math.floor(this.next() * (max - min + 1)) + min;
    78тЖТ  }
    79тЖТ}
    80тЖТ
    81тЖТ// =============================================================================
    82тЖТ// Helper Functions
    83тЖТ// =============================================================================
    84тЖТ
    85тЖТfunction addDays(date: Date, days: number): Date {
    86тЖТ  const result = new Date(date);
    87тЖТ  result.setDate(result.getDate() + days);
    88тЖТ  return result;
    89тЖТ}
    90тЖТ
    91тЖТfunction addMonths(date: Date, months: number): Date {
    92тЖТ  const result = new Date(date);
    93тЖТ  result.setMonth(result.getMonth() + months);
    94тЖТ  return result;
    95тЖТ}
    96тЖТ
    97тЖТfunction formatYearMonth(date: Date): string {
    98тЖТ  return `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}`;
    99тЖТ}
   100тЖТ
   101тЖТ// =============================================================================
   102тЖТ// Chaos Monkey Implementation
   103тЖТ// =============================================================================
   104тЖТ
   105тЖТ/**
   106тЖТ * Apply chaos monkey disruption to PM projections
   107тЖТ *
   108тЖТ * Simulates a supply chain disruption that:
   109тЖТ * 1. Delays all PMs in the disruption window
   110тЖТ * 2. Compresses PMs into a recovery period
   111тЖТ * 3. Creates a visible bow-wave effect
   112тЖТ *
   113тЖТ * @param projections - Original PM projections
   114тЖТ * @param config - Disruption configuration
   115тЖТ * @returns Modified projections with bow-wave effect
   116тЖТ */
   117тЖТexport function applyChaosMonkey(
   118тЖТ  projections: ProjectedPM[],
   119тЖТ  config: ChaosConfig = {}
   120тЖТ): ChaosResult {
   121тЖТ  const {
   122тЖТ    delayMonths = 3,
   123тЖТ    disruptionStartMonth = 6,
   124тЖТ    affectRate = 0.7,
   125тЖТ    seed = Date.now(),
   126тЖТ  } = config;
   127тЖТ
   128тЖТ  const rng = new SeededRandom(seed);
   129тЖТ  const today = new Date();
   130тЖТ  today.setHours(0, 0, 0, 0);
   131тЖТ
   132тЖТ  // Calculate disruption window
   133тЖТ  const disruptionStart = addMonths(today, disruptionStartMonth);
   134тЖТ  const disruptionEnd = addMonths(disruptionStart, delayMonths);
   135тЖТ
   136тЖТ  // Deep copy projections for modification
   137тЖТ  const modified: ProjectedPM[] = projections.map((pm) => ({
   138тЖТ    ...pm,
   139тЖТ    projectedDate: new Date(pm.projectedDate),
   140тЖТ  }));
   141тЖТ
   142тЖТ  let affected = 0;
   143тЖТ  let totalDelayDays = 0;
   144тЖТ
   145тЖТ  // Apply disruption: delay PMs that fall within the disruption window
   146тЖТ  for (const pm of modified) {
   147тЖТ    const pmDate = pm.projectedDate;
   148тЖТ
   149тЖТ    // Check if PM falls within disruption window
   150тЖТ    const inDisruptionWindow =
   151тЖТ      pmDate >= disruptionStart && pmDate < disruptionEnd;
   152тЖТ
   153тЖТ    // Also delay PMs that are scheduled shortly after (recovery crunch)
   154тЖТ    const inRecoveryPeriod =
   155тЖТ      pmDate >= disruptionEnd &&
   156тЖТ      pmDate < addMonths(disruptionEnd, Math.ceil(delayMonths / 2));
   157тЖТ
   158тЖТ    if (inDisruptionWindow && rng.next() < affectRate) {
   159тЖТ      // Delay PM to after disruption end (compress into recovery period)
   160тЖТ      const daysUntilDisruptionEnd = Math.ceil(
   161тЖТ        (disruptionEnd.getTime() - pmDate.getTime()) / (1000 * 60 * 60 * 24)
   162тЖТ      );
   163тЖТ
   164тЖТ      // Add some variance to create clustering
   165тЖТ      const extraDelay = rng.range(0, 14);
   166тЖТ      const totalDelay = daysUntilDisruptionEnd + extraDelay;
   167тЖТ
   168тЖТ      pm.projectedDate = addDays(pm.projectedDate, totalDelay);
   169тЖТ
   170тЖТ      affected++;
   171тЖТ      totalDelayDays += totalDelay;
   172тЖТ    } else if (inRecoveryPeriod && rng.next() < affectRate * 0.5) {
   173тЖТ      // Compress some recovery period PMs for more dramatic clustering
   174тЖТ      const compressDays = rng.range(7, 21);
   175тЖТ
   176тЖТ      pm.projectedDate = addDays(pm.projectedDate, -compressDays);
   177тЖТ
   178тЖТ      affected++;
   179тЖТ      totalDelayDays += compressDays;
   180тЖТ    }
   181тЖТ  }
   182тЖТ
   183тЖТ  // Calculate peak month statistics
   184тЖТ  const monthCounts = new Map<string, number>();
   185тЖТ  for (const pm of modified) {
   186тЖТ    const key = formatYearMonth(pm.projectedDate);
   187тЖТ    monthCounts.set(key, (monthCounts.get(key) || 0) + 1);
   188тЖТ  }
   189тЖТ
   190тЖТ  let peakMonth = '';
   191тЖТ  let peakCount = 0;
   192тЖТ  for (const [month, count] of monthCounts) {
   193тЖТ    if (count > peakCount) {
   194тЖТ      peakMonth = month;
   195тЖТ      peakCount = count;
   196тЖТ    }
   197тЖТ  }
   198тЖТ
   199тЖТ  // Generate description for demo narration
   200тЖТ  const disruptionStartStr = disruptionStart.toLocaleDateString('en-US', {
   201тЖТ    month: 'long',
   202тЖТ    year: 'numeric',
   203тЖТ  });
   204тЖТ  const description =
   205тЖТ    `Simulating a ${delayMonths}-month supply chain disruption starting ${disruptionStartStr}. ` +
   206тЖТ    `${affected} PMs delayed, creating a bow-wave peak in ${peakMonth} with ${peakCount} PMs.`;
   207тЖТ
   208тЖТ  return {
   209тЖТ    original: projections,
   210тЖТ    modified,
   211тЖТ    description,
   212тЖТ    stats: {
   213тЖТ      affected,
