/**
 * MMS Chaos Monkey - Bow-Wave Generator
 *
 * DEMO ONLY - Not for production use.
 *
 * Purpose: If the client's data is well-maintained (no bow-wave), the demo loses impact.
 * This feature artificially compresses PM schedules to force a visible bow-wave.
 *
 * Usage:
 * - URL param: ?chaos=true
 * - Shift+Click on BowWaveIndicator
 *
 * Pitch: "This is your data as-is. Now, let's simulate a 3-month
 *        supply chain disruption..." (Toggle) тЖТ "See that wave forming?"
 *
 * @see specs/009-demo-application.md Section 9.3.3
 */

import type { ProjectedPM } from './types';

// =============================================================================
// Types
// =============================================================================

/** Configuration for chaos monkey disruption */
export interface ChaosConfig {
  /** How long the "disruption" lasts in months (default: 3) */
  delayMonths?: number;
  /** Start month of disruption (default: 6 months from now) */
  disruptionStartMonth?: number;
  /** What percentage of PMs to affect (default: 0.7 = 70%) */
  affectRate?: number;
  /** Random seed for reproducibility (optional) */
  seed?: number;
}

/** Result of chaos monkey application */
export interface ChaosResult {
  /** Original projections (unmodified) */
  original: ProjectedPM[];
  /** Modified projections with bow-wave effect */
  modified: ProjectedPM[];
  /** Description of the disruption for demo narration */
  description: string;
  /** Statistics about the disruption */
  stats: {
    /** Number of PMs affected */
    affected: number;
    /** Number of PMs unchanged */
    unchanged: number;
    /** Average delay in days */
    avgDelayDays: number;
    /** Peak month after disruption */
    peakMonth: string;
    /** Peak month PM count */
    peakCount: number;
  };
}

// =============================================================================
// Seeded Random for Reproducibility
// =============================================================================

class SeededRandom {
  private seed: number;

  constructor(seed: number) {
    this.seed = seed;
  }

  next(): number {
    this.seed = (this.seed * 1103515245 + 12345) & 0x7fffffff;
    return this.seed / 0x7fffffff;
  }

  range(min: number, max: number): number {
    return Math.floor(this.next() * (max - min + 1)) + min;
  }
}

// =============================================================================
// Helper Functions
// =============================================================================

function addDays(date: Date, days: number): Date {
  const result = new Date(date);
  result.setDate(result.getDate() + days);
  return result;
}

function addMonths(date: Date, months: number): Date {
  const result = new Date(date);
  result.setMonth(result.getMonth() + months);
  return result;
}

function formatYearMonth(date: Date): string {
  return `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}`;
}

// =============================================================================
// Chaos Monkey Implementation
// =============================================================================

/**
 * Apply chaos monkey disruption to PM projections
 *
 * Simulates a supply chain disruption that:
 * 1. Delays all PMs in the disruption window
 * 2. Compresses PMs into a recovery period
 * 3. Creates a visible bow-wave effect
 *
 * @param projections - Original PM projections
 * @param config - Disruption configuration
 * @returns Modified projections with bow-wave effect
 */
export function applyChaosMonkey(
  projections: ProjectedPM[],
  config: ChaosConfig = {}
): ChaosResult {
  const {
    delayMonths = 3,
    disruptionStartMonth = 6,
    affectRate = 0.7,
    seed = Date.now(),
  } = config;

  const rng = new SeededRandom(seed);
  const today = new Date();
  today.setHours(0, 0, 0, 0);

  // Calculate disruption window
  const disruptionStart = addMonths(today, disruptionStartMonth);
  const disruptionEnd = addMonths(disruptionStart, delayMonths);

  // Deep copy projections for modification
  const modified: ProjectedPM[] = projections.map((pm) => ({
    ...pm,
    projectedDate: new Date(pm.projectedDate),
  }));

  let affected = 0;
  let totalDelayDays = 0;

  // Apply disruption: delay PMs that fall within the disruption window
  for (const pm of modified) {
    const pmDate = pm.projectedDate;

    // Check if PM falls within disruption window
    const inDisruptionWindow =
      pmDate >= disruptionStart && pmDate < disruptionEnd;

    // Also delay PMs that are scheduled shortly after (recovery crunch)
    const inRecoveryPeriod =
      pmDate >= disruptionEnd &&
      pmDate < addMonths(disruptionEnd, Math.ceil(delayMonths / 2));

    if (inDisruptionWindow && rng.next() < affectRate) {
      // Delay PM to after disruption end (compress into recovery period)
      const daysUntilDisruptionEnd = Math.ceil(
        (disruptionEnd.getTime() - pmDate.getTime()) / (1000 * 60 * 60 * 24)
      );

      // Add some variance to create clustering
      const extraDelay = rng.range(0, 14);
      const totalDelay = daysUntilDisruptionEnd + extraDelay;

      pm.projectedDate = addDays(pm.projectedDate, totalDelay);

      affected++;
      totalDelayDays += totalDelay;
    } else if (inRecoveryPeriod && rng.next() < affectRate * 0.5) {
      // Compress some recovery period PMs for more dramatic clustering
      const compressDays = rng.range(7, 21);

      pm.projectedDate = addDays(pm.projectedDate, -compressDays);

      affected++;
      totalDelayDays += compressDays;
    }
  }

  // Calculate peak month statistics
  const monthCounts = new Map<string, number>();
  for (const pm of modified) {
    const key = formatYearMonth(pm.projectedDate);
    monthCounts.set(key, (monthCounts.get(key) || 0) + 1);
  }

  let peakMonth = '';
  let peakCount = 0;
  for (const [month, count] of monthCounts) {
    if (count > peakCount) {
      peakMonth = month;
      peakCount = count;
    }
  }

  // Generate description for demo narration
  const disruptionStartStr = disruptionStart.toLocaleDateString('en-US', {
    month: 'long',
    year: 'numeric',
  });
  const description =
    `Simulating a ${delayMonths}-month supply chain disruption starting ${disruptionStartStr}. ` +
    `${affected} PMs delayed, creating a bow-wave peak in ${peakMonth} with ${peakCount} PMs.`;

  return {
    original: projections,
    modified,
    description,
    stats: {
      affected,
      unchanged: projections.length - affected,
      avgDelayDays: affected > 0 ? Math.round(totalDelayDays / affected) : 0,
      peakMonth,
      peakCount,
    },
  };
}

// =============================================================================
// URL Parameter Detection
// =============================================================================

/**
 * Check if chaos monkey is enabled via URL parameter
 *
 * @returns true if ?chaos=true or ?chaos_monkey=true is in URL
 */
export function isChaosMonkeyEnabled(): boolean {
  if (typeof window === 'undefined') return false;

  const params = new URLSearchParams(window.location.search);
  return (
    params.get('chaos') === 'true' ||
    params.get('chaos_monkey') === 'true' ||
    params.get('bowwave') === 'true'
  );
}

/**
 * Toggle chaos monkey URL parameter
 *
 * @param enable - Whether to enable or disable
 */
export function toggleChaosMonkeyUrl(enable: boolean): void {
  if (typeof window === 'undefined') return;

  const url = new URL(window.location.href);

  if (enable) {
    url.searchParams.set('chaos', 'true');
  } else {
    url.searchParams.delete('chaos');
    url.searchParams.delete('chaos_monkey');
    url.searchParams.delete('bowwave');
  }

  window.history.replaceState({}, '', url.toString());
}

// =============================================================================
// Preset Configurations
// =============================================================================

/** 3-month supply chain disruption (default demo scenario) */
export const CHAOS_PRESET_SUPPLY_CHAIN: ChaosConfig = {
  delayMonths: 3,
  disruptionStartMonth: 6,
  affectRate: 0.7,
};

/** 6-month pandemic-style disruption */
export const CHAOS_PRESET_PANDEMIC: ChaosConfig = {
  delayMonths: 6,
  disruptionStartMonth: 3,
  affectRate: 0.85,
};

/** 2-month parts shortage */
export const CHAOS_PRESET_PARTS_SHORTAGE: ChaosConfig = {
  delayMonths: 2,
  disruptionStartMonth: 4,
  affectRate: 0.5,
};

/** 4-month labor shortage */
export const CHAOS_PRESET_LABOR_SHORTAGE: ChaosConfig = {
  delayMonths: 4,
  disruptionStartMonth: 8,
  affectRate: 0.6,
};

