     1тЖТ/**
     2тЖТ * Drag Validation Utilities
     3тЖТ *
     4тЖТ * Helpers for validating PM drag-and-drop operations including:
     5тЖТ * - Real-time constraint validation API calls
     6тЖТ * - Debounced validation for performance
     7тЖТ * - Impact assessment calculation
     8тЖТ *
     9тЖТ * @see specs/006-user-interface.md Section 6.3.4
    10тЖТ */
    11тЖТ
    12тЖТimport type { DragValidationState, DragConstraintViolation, PmMoveImpact } from '../layers/types';
    13тЖТ
    14тЖТ// =============================================================================
    15тЖТ// Types
    16тЖТ// =============================================================================
    17тЖТ
    18тЖТexport interface ValidatePmMoveParams {
    19тЖТ  pmId: string;
    20тЖТ  currentDate: string;
    21тЖТ  targetDate: string;
    22тЖТ  trainId: string;
    23тЖТ}
    24тЖТ
    25тЖТexport interface ValidatePmMoveResponse {
    26тЖТ  isValid: boolean;
    27тЖТ  violations: DragConstraintViolation[];
    28тЖТ  impact?: PmMoveImpact;
    29тЖТ}
    30тЖТ
    31тЖТ// =============================================================================
    32тЖТ// Validation API
    33тЖТ// =============================================================================
    34тЖТ
    35тЖТ/**
    36тЖТ * Validates a PM move against all constraints.
    37тЖТ * Returns validation state including violations and impact assessment.
    38тЖТ */
    39тЖТexport async function validatePmMove(
    40тЖТ  params: ValidatePmMoveParams,
    41тЖТ  options: { baseUrl?: string; signal?: AbortSignal } = {}
    42тЖТ): Promise<DragValidationState> {
    43тЖТ  const { baseUrl = '/api/v1', signal } = options;
    44тЖТ
    45тЖТ  try {
    46тЖТ    const response = await fetch(`${baseUrl}/pm/schedule/${params.pmId}/validate-move`, {
    47тЖТ      method: 'POST',
    48тЖТ      headers: {
    49тЖТ        'Content-Type': 'application/json',
    50тЖТ      },
    51тЖТ      body: JSON.stringify({
    52тЖТ        targetDate: params.targetDate,
    53тЖТ        trainId: params.trainId,
    54тЖТ      }),
    55тЖТ      signal,
    56тЖТ    });
    57тЖТ
    58тЖТ    if (!response.ok) {
    59тЖТ      // Handle specific error codes
    60тЖТ      if (response.status === 409) {
    61тЖТ        // Conflict - PM is locked in Maximo
    62тЖТ        return {
    63тЖТ          isValid: false,
    64тЖТ          message: 'PM is locked in Maximo (in progress)',
    65тЖТ          violations: [{
    66тЖТ            type: 'MAXIMO_LOCK',
    67тЖТ            severity: 'ERROR',
    68тЖТ            message: 'Cannot reschedule: PM is currently in progress in Maximo',
    69тЖТ          }],
    70тЖТ        };
    71тЖТ      }
    72тЖТ
    73тЖТ      throw new Error(`Validation failed: ${response.statusText}`);
    74тЖТ    }
    75тЖТ
    76тЖТ    const data = await response.json() as { data: ValidatePmMoveResponse };
    77тЖТ    const result = data.data;
    78тЖТ
    79тЖТ    return {
    80тЖТ      isValid: result.isValid,
    81тЖТ      message: result.violations.length > 0
    82тЖТ        ? result.violations.map(v => v.message).join('; ')
    83тЖТ        : null,
    84тЖТ      violations: result.violations,
    85тЖТ    };
    86тЖТ  } catch (error) {
    87тЖТ    // If request was aborted, return neutral state
    88тЖТ    if (error instanceof Error && error.name === 'AbortError') {
    89тЖТ      return {
    90тЖТ        isValid: true,
    91тЖТ        message: null,
    92тЖТ        violations: [],
    93тЖТ      };
    94тЖТ    }
    95тЖТ
    96тЖТ    // For network errors, return a warning (not blocking)
    97тЖТ    return {
    98тЖТ      isValid: true,
    99тЖТ      message: 'Unable to validate constraints (network error)',
   100тЖТ      violations: [{
   101тЖТ        type: 'SERVICE_DEMAND',
   102тЖТ        severity: 'WARNING',
   103тЖТ        message: 'Constraint validation unavailable - proceed with caution',
   104тЖТ      }],
   105тЖТ    };
   106тЖТ  }
   107тЖТ}
