/**
 * Drag Validation Utilities
 *
 * Helpers for validating PM drag-and-drop operations including:
 * - Real-time constraint validation API calls
 * - Debounced validation for performance
 * - Impact assessment calculation
 *
 * @see specs/006-user-interface.md Section 6.3.4
 */

import type { DragValidationState, DragConstraintViolation, PmMoveImpact } from '../layers/types';

// =============================================================================
// Types
// =============================================================================

export interface ValidatePmMoveParams {
  pmId: string;
  currentDate: string;
  targetDate: string;
  trainId: string;
}

export interface ValidatePmMoveResponse {
  isValid: boolean;
  violations: DragConstraintViolation[];
  impact?: PmMoveImpact;
}

// =============================================================================
// Validation API
// =============================================================================

/**
 * Validates a PM move against all constraints.
 * Returns validation state including violations and impact assessment.
 */
export async function validatePmMove(
  params: ValidatePmMoveParams,
  options: { baseUrl?: string; signal?: AbortSignal } = {}
): Promise<DragValidationState> {
  const { baseUrl = '/api/v1', signal } = options;

  try {
    const response = await fetch(`${baseUrl}/pm/schedule/${params.pmId}/validate-move`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        targetDate: params.targetDate,
        trainId: params.trainId,
      }),
      signal,
    });

    if (!response.ok) {
      // Handle specific error codes
      if (response.status === 409) {
        // Conflict - PM is locked in Maximo
        return {
          isValid: false,
          message: 'PM is locked in Maximo (in progress)',
          violations: [{
            type: 'MAXIMO_LOCK',
            severity: 'ERROR',
            message: 'Cannot reschedule: PM is currently in progress in Maximo',
          }],
        };
      }

      throw new Error(`Validation failed: ${response.statusText}`);
    }

    const data = await response.json() as { data: ValidatePmMoveResponse };
    const result = data.data;

    return {
      isValid: result.isValid,
      message: result.violations.length > 0
        ? result.violations.map(v => v.message).join('; ')
        : null,
      violations: result.violations,
    };
  } catch (error) {
    // If request was aborted, return neutral state
    if (error instanceof Error && error.name === 'AbortError') {
      return {
        isValid: true,
        message: null,
        violations: [],
      };
    }

    // For network errors, return a warning (not blocking)
    return {
      isValid: true,
      message: 'Unable to validate constraints (network error)',
      violations: [{
        type: 'SERVICE_DEMAND',
        severity: 'WARNING',
        message: 'Constraint validation unavailable - proceed with caution',
      }],
    };
  }
}

/**
 * Client-side quick validation for immediate feedback.
 * Checks basic constraints without API call.
 */
export function quickValidatePmMove(
  params: ValidatePmMoveParams & {
    constraintStart: string;
    constraintEnd: string;
    isLocked: boolean;
  }
): DragValidationState {
  const violations: DragConstraintViolation[] = [];

  // Check if PM is locked
  if (params.isLocked) {
    violations.push({
      type: 'MAXIMO_LOCK',
      severity: 'ERROR',
      message: 'Cannot move: PM is locked',
    });
  }

  // Check compliance window
  const targetDate = new Date(params.targetDate);
  const windowStart = new Date(params.constraintStart);
  const windowEnd = new Date(params.constraintEnd);

  if (targetDate < windowStart) {
    violations.push({
      type: 'COMPLIANCE_WINDOW',
      severity: 'ERROR',
      message: `Target date ${params.targetDate} is before compliance window start (${params.constraintStart})`,
    });
  }

  if (targetDate > windowEnd) {
    violations.push({
      type: 'COMPLIANCE_WINDOW',
      severity: 'ERROR',
      message: `Target date ${params.targetDate} is after compliance window end (${params.constraintEnd})`,
    });
  }

  // Check if same date (no change)
  if (params.currentDate === params.targetDate) {
    return {
      isValid: true,
      message: null,
      violations: [],
    };
  }

  const hasErrors = violations.some(v => v.severity === 'ERROR');

  return {
    isValid: !hasErrors,
    message: violations.length > 0
      ? violations.map(v => v.message).join('; ')
      : null,
    violations,
  };
}

// =============================================================================
// Debounced Validation
// =============================================================================

interface DebouncedValidation {
  validate: (params: ValidatePmMoveParams) => void;
  cancel: () => void;
}

/**
 * Creates a debounced validation function for real-time drag feedback.
 * Cancels previous pending validation when a new position is provided.
 */
export function createDebouncedValidation(
  onResult: (result: DragValidationState) => void,
  options: { delay?: number; baseUrl?: string } = {}
): DebouncedValidation {
  const { delay = 150, baseUrl = '/api/v1' } = options;

  let timeoutId: NodeJS.Timeout | null = null;
  let abortController: AbortController | null = null;

  const validate = (params: ValidatePmMoveParams) => {
    // Cancel previous
    if (timeoutId) {
      clearTimeout(timeoutId);
    }
    if (abortController) {
      abortController.abort();
    }

    // Create new abort controller
    abortController = new AbortController();
    const signal = abortController.signal;

    // Schedule new validation
    timeoutId = setTimeout(async () => {
      const result = await validatePmMove(params, { baseUrl, signal });
      if (!signal.aborted) {
        onResult(result);
      }
    }, delay);
  };

  const cancel = () => {
    if (timeoutId) {
      clearTimeout(timeoutId);
      timeoutId = null;
    }
    if (abortController) {
      abortController.abort();
      abortController = null;
    }
  };

  return { validate, cancel };
}

// =============================================================================
// Impact Assessment
// =============================================================================

/**
 * Fetches detailed impact assessment for a PM move.
 * Used for the confirmation dialog.
 */
export async function getPmMoveImpact(
  params: ValidatePmMoveParams,
  options: { baseUrl?: string } = {}
): Promise<PmMoveImpact | null> {
  const { baseUrl = '/api/v1' } = options;

  try {
    const response = await fetch(`${baseUrl}/pm/schedule/${params.pmId}/move-impact`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        targetDate: params.targetDate,
        currentDate: params.currentDate,
      }),
    });

    if (!response.ok) {
      return null;
    }

    const data = await response.json() as { data: PmMoveImpact };
    return data.data;
  } catch {
    return null;
  }
}

/**
 * Commits a PM move to the server.
 * Returns true on success, throws on failure.
 */
export async function commitPmMove(
  params: ValidatePmMoveParams & { reason?: string },
  options: { baseUrl?: string } = {}
): Promise<{ success: boolean; explanation?: string }> {
  const { baseUrl = '/api/v1' } = options;

  const response = await fetch(`${baseUrl}/pm/schedule/${params.pmId}`, {
    method: 'PATCH',
    headers: {
      'Content-Type': 'application/json',
    },
    body: JSON.stringify({
      targetDate: params.targetDate,
      reason: params.reason || 'Manual reschedule via canvas drag-and-drop',
    }),
  });

  if (!response.ok) {
    const error = await response.json() as { error?: { message?: string } };
    throw new Error(error.error?.message || 'Failed to reschedule PM');
  }

  const data = await response.json() as {
    data: { explanation?: { changeType: string; impactAssessment: string } };
  };

  return {
    success: true,
    explanation: data.data.explanation?.impactAssessment,
  };
}

