/**
 * MMS Bow-Wave Scenario Analyzer
 *
 * Analyzes generated demo data to:
 * - Project future PM events based on current mileage and history
 * - Identify Q2 2027 maintenance clustering (bow-wave)
 * - Flag 40% C4 overlap violations
 * - Calculate capital risk concentration ($15M threshold)
 * - Generate visualization data (heatmap density, Gantt bars)
 *
 * @see specs/009-demo-application.md
 */

import { formatDate } from './generator';
import type {
  BowWaveAnalysis,
  BowWaveScenarioOutput,
  DemoPMHistory,
  DemoTrain,
  GanttBar,
  GeneratedData,
  MonthlyPMDensity,
  ProjectedPM,
} from './types';

/** Average C4 overhaul cost in millions */
const C4_COST_MILLIONS = 0.3;

/** Weekly man-hour capacity (40 hours x 5 technicians) */
const WEEKLY_MAN_HOUR_CAPACITY = 200;

/** Critical threshold: >15 PMs per month */
const CRITICAL_PM_THRESHOLD = 15;

/** Overlap violation threshold: 40% of fleet */
const OVERLAP_VIOLATION_THRESHOLD = 0.4;

/** Add days to a date */
function addDays(date: Date, days: number): Date {
  const result = new Date(date);
  result.setDate(result.getDate() + days);
  return result;
}

/** Get year-month string from date */
function getYearMonth(date: Date): string {
  const year = date.getFullYear();
  const month = String(date.getMonth() + 1).padStart(2, '0');
  return `${year}-${month}`;
}

/** Get quarter string from date (Q1-Q4 YYYY) */
function getQuarter(date: Date): string {
  const year = date.getFullYear();
  const quarter = Math.floor(date.getMonth() / 3) + 1;
  return `Q${quarter} ${year}`;
}

/** Calculate days between two dates */
function daysBetween(a: Date, b: Date): number {
  const msPerDay = 24 * 60 * 60 * 1000;
  return Math.floor((b.getTime() - a.getTime()) / msPerDay);
}

interface PmTypeInfo {
  id: string;
  pmCode: string;
  intervalKm: number;
  intervalMonths: number;
  estimatedHours: number;
  displayColor: string;
}

/**
 * Project future PM events for a train based on current state and history
 */
function projectTrainPMs(
  train: DemoTrain,
  pmTypes: PmTypeInfo[],
  pmHistory: DemoPMHistory[],
  horizonDate: Date,
  today: Date
): ProjectedPM[] {
  const projections: ProjectedPM[] = [];

  // Get train's PM history
  const trainHistory = pmHistory.filter((pm) => pm.trainId === train.id);

  for (const pmType of pmTypes) {
    // Find the most recent completion of this PM type
    const lastCompletion = trainHistory
      .filter((pm) => pm.pmTypeId === pmType.id)
      .sort((a, b) => b.completionDate.getTime() - a.completionDate.getTime())[0];

    // Calculate next due date using dual triggers (mileage and time)
    let nextDueDate: Date;
    let nextDueMileage: number;

    if (lastCompletion) {
      // Calculate from last completion
      const mileageSinceCompletion = train.currentMileageKm - lastCompletion.completedMileageKm;
      const kmToNextPm = pmType.intervalKm - mileageSinceCompletion;
      const daysToMileageDue = Math.max(0, Math.round(kmToNextPm / train.estimatedDailyKm));

      const daysSinceCompletion = daysBetween(lastCompletion.completionDate, today);
      const daysToTimeDue = Math.max(0, pmType.intervalMonths * 30 - daysSinceCompletion);

      // Dual trigger: whichever comes first
      const daysToNextPm = Math.min(daysToMileageDue, daysToTimeDue);
      nextDueDate = addDays(today, daysToNextPm);
      nextDueMileage = train.currentMileageKm + daysToNextPm * train.estimatedDailyKm;
    } else {
      // Cold start: assume PM was done at commissioning on-schedule
      const daysSinceCommissioning = daysBetween(train.commissioningDate, today);
      const cyclesFromCommissioning = Math.floor(train.currentMileageKm / pmType.intervalKm);
      const lastPmMileage = cyclesFromCommissioning * pmType.intervalKm;

      const kmToNextPm = pmType.intervalKm - (train.currentMileageKm - lastPmMileage);
      const daysToMileageDue = Math.max(0, Math.round(kmToNextPm / train.estimatedDailyKm));

      const monthsIntoCurrentCycle = (daysSinceCommissioning / 30) % pmType.intervalMonths;
      const daysToTimeDue = Math.max(0, (pmType.intervalMonths - monthsIntoCurrentCycle) * 30);

      const daysToNextPm = Math.min(daysToMileageDue, daysToTimeDue);
      nextDueDate = addDays(today, daysToNextPm);
      nextDueMileage = train.currentMileageKm + daysToNextPm * train.estimatedDailyKm;
    }

    // Project all PMs within horizon
    let currentDate = nextDueDate;
    let currentMileage = nextDueMileage;

    while (currentDate <= horizonDate) {
      projections.push({
        trainId: train.id,
        trainNumber: train.trainNumber,
        fleetCode: train.fleetCode,
        pmTypeId: pmType.id,
        pmCode: pmType.pmCode,
        projectedDate: new Date(currentDate),
        projectedMileage: Math.round(currentMileage),
        estimatedHours: pmType.estimatedHours,
        displayColor: pmType.displayColor,
      });

      // Calculate next interval
      const intervalDays = Math.round(pmType.intervalKm / train.estimatedDailyKm);
      const timeDays = pmType.intervalMonths * 30;
      const nextInterval = Math.min(intervalDays, timeDays);

